import React from 'react';

interface ProductCardProps {
  title: string;
  description: string;
  imageUrl: string;
}

const ProductCard: React.FC<ProductCardProps> = ({ title, description, imageUrl }) => {
  return (
    <div className="p-6 bg-white rounded-xl shadow-md">
      <img src={imageUrl} alt={title} className="w-full h-48 object-cover rounded-t-xl" />
      <div className="p-4">
        <h3 className="text-xl font-bold mb-2">{title}</h3>
        <p className="text-gray-700 mb-4">{description}</p>
        <button className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">Add to Cart</button>
      </div>
    </div>
  );
};

export default ProductCard;

